author: WidgeTDC Platform
date: 2026-04-04
version: 5.2.0
license: MIT
description: SITREP Engine - natural language to 6-line posture briefs with sparklines. Domain compiler learns your organization. Monday Morning Email killer. Kill templates, embrace improvisation.
requirements: aiohttp
"""

from pydantic import BaseModel, Field
import aiohttp
import asyncio
import json
import logging
import html as html_mod
import hashlib
import time
from datetime import datetime, timezone

logger = logging.getLogger(__name__)

# === Intent keywords for fast-path routing (minimal, no templates) ===
HINTS = {
    "compliance": {"tool": "graph.read_cypher", "payload": {"query": "MATCH (c:ComplianceSnapshot) RETURN c.domain AS domain, c.score AS score, c.grade AS grade ORDER BY c.timestamp DESC LIMIT 10"}},
    "audit": {"tool": "graph.read_cypher", "payload": {"query": "MATCH (f:FailureMemory) RETURN f.type AS type, f.correction AS correction ORDER BY f.timestamp DESC LIMIT 10"}},
    "health": {"tool": "graph.health", "payload": {}},
    "stats": {"tool": "graph.stats", "payload": {}},
    "agents": {"tool": "graph.read_cypher", "payload": {"query": "MATCH (a:Agent) RETURN a.id AS agent, a.role AS role, a.status AS status ORDER BY a.lastSeen DESC LIMIT 12"}},
    "tickets": {"tool": "linear.issues", "payload": {"limit": 12}},
    "issues": {"tool": "linear.issues", "payload": {"limit": 12}},
    "sprint": {"tool": "linear.issues", "payload": {"limit": 12, "state": "In Progress"}},
    "blockers": {"tool": "linear.issues", "payload": {"limit": 10, "priority": "Urgent"}},
    "cve": {"tool": "graph.read_cypher", "payload": {"query": "MATCH (c:CVE) RETURN c.id AS cve, c.severity AS severity ORDER BY c.severity DESC LIMIT 10"}},
    "security": {"tool": "graph.read_cypher", "payload": {"query": "MATCH (c:CVE) WHERE c.severity IN ['CRITICAL','HIGH'] RETURN c.id AS cve, c.severity AS severity LIMIT 10"}},
    "clients": {"tool": "graph.read_cypher", "payload": {"query": "MATCH (o:Organization) RETURN o.name AS client, o.sector AS sector LIMIT 15"}},
    "risks": {"tool": "graph.read_cypher", "payload": {"query": "MATCH (c:ComplianceSnapshot) WHERE c.score < 70 RETURN c.domain AS area, c.score AS score ORDER BY c.score LIMIT 8"}},
    "incidents": {"tool": "graph.read_cypher", "payload": {"query": "MATCH (f:FailureMemory) WHERE f.timestamp > datetime() - duration({days: 7}) RETURN f.type AS type ORDER BY f.timestamp DESC LIMIT 8"}},
}

SEV_EMOJI = {"CRITICAL": "\U0001f534", "HIGH": "\U0001f7e0", "MEDIUM": "\U0001f7e1", "LOW": "\U0001f7e2"}
GRADE_EMOJI = {"A": "\U0001f3c6", "B": "\U0001f948", "C": "\U0001f949", "D": "\u26a0\ufe0f", "F": "\u274c"}

# === Unicode viz helpers (Qwen-generated) ===
def sparkline(data):
    if not data:
        return ""
    nums = []
    for v in data:
        try:
            nums.append(float(str(v).replace(",", "")))
        except:
            pass
    if not nums:
        return ""
    mn, mx = min(nums), max(nums)
    if mn == mx:
        return "\u2588" * min(len(nums), 20)
    chars = "\u2581\u2582\u2583\u2584\u2585\u2586\u2587\u2588"
    out = ""
    for v in nums[:20]:
        idx = int(((v - mn) / (mx - mn)) * 7)
        out += chars[max(0, min(7, idx))]
    return out

def progress_bar(pct, width=20):
    pct = max(0.0, min(100.0, float(pct)))
    filled = int((pct / 100.0) * width)
    full_char = "\u2588"
    empty_char = "\u2591"
    bar = full_char * filled + empty_char * (width - filled)
    return f"[{bar}] {int(round(pct))}%"

def trend(old, new):
    try:
        old, new = float(old), float(new)
    except:
        return ""
    if old == 0:
        return "\u2192 0%"
    ch = ((new - old) / old) * 100
    if new > old:
        return f"\u25b2 +{ch:.1f}%"
    if new < old:
        return f"\u25bc {ch:.1f}%"
    return "\u2192 0%"

def sev_emoji(s):
    return SEV_EMOJI.get(str(s).strip().upper(), "\u26aa")

def grade_emoji(g):
    return GRADE_EMOJI.get(str(g).strip().upper(), "\u26aa")

def fmt_num(n):
    if n is None:
        return "0"
    try:
        n = float(str(n).replace(",", "")) if isinstance(n, str) else float(n)
    except:
        return str(n)
    if n < 0:
        return "-" + fmt_num(-n)
    if n < 1000:
        return str(int(n)) if n == int(n) else f"{n:.1f}"
    for lim, sfx in [(1e3, "K"), (1e6, "M"), (1e9, "B"), (1e12, "T")]:
        if n < lim * 1000:
            return f"{n/lim:.1f}{sfx}"
    return f"{n/1e12:.1f}T"


class Tools:
    class Valves(BaseModel):
        BACKEND_URL: str = Field(default="https://backend-production-d3da.up.railway.app", description="WidgeTDC Backend URL")
        BACKEND_API_KEY: str = Field(default="", description="Backend API key")
        ENABLE_COMPILER: bool = Field(default=True, description="Enable domain compiler (learns org vocabulary)")
        DRY_VOICE: bool = Field(default=True, description="Terse 2am-analyst voice (vs verbose)")

    def __init__(self):
        self.valves = self.Valves()
        self._cache = {}
        self._cache_ttl = {"graph.health": 15, "graph.stats": 60}


    def _envelope(self, content: str, method_name: str) -> str:
        """Wrap display-as-is output in directive envelope so LLM renders verbatim."""
        top = "[TOOL_OUTPUT:" + method_name + "]"
        directive = "PRESENT THE FOLLOWING MARKDOWN VERBATIM. Do not paraphrase. Do not summarize. This is the final answer - copy it exactly, then add one optional sentence if helpful."
        bottom = "[END_TOOL_OUTPUT]"
        NL = chr(10)
        return top + NL + directive + NL + NL + content + NL + NL + bottom

    # === CORE MCP CALL WITH RETRY + CACHE ===
    async def _mcp_call(self, session, tool, payload, max_retries=2):
        cache_key = f"{tool}:{json.dumps(payload, sort_keys=True)}"
        ttl = self._cache_ttl.get(tool, 0)
        if ttl > 0 and cache_key in self._cache:
            cached_at, cached_val = self._cache[cache_key]
            if time.time() - cached_at < ttl:
                return cached_val
        url = f"{self.valves.BACKEND_URL}/api/mcp/route"
        headers = {"Authorization": f"Bearer {self.valves.BACKEND_API_KEY}", "Content-Type": "application/json"}
        body = {"tool": tool, "payload": payload}
        timeout = aiohttp.ClientTimeout(total=25)
        for attempt in range(max_retries + 1):
            try:
                async with session.post(url, headers=headers, json=body, timeout=timeout) as r:
                    if r.status in (502, 503, 504) and attempt < max_retries:
                        await asyncio.sleep((2 ** attempt) * 0.5)
                        continue
                    r.raise_for_status()
                    d = await r.json()
                    result = d.get("result", d)
                    if ttl > 0:
                        self._cache[cache_key] = (time.time(), result)
                    return result
            except Exception:
                if attempt == max_retries:
                    raise
                await asyncio.sleep((2 ** attempt) * 0.5)
        raise RuntimeError("unreachable")

    async def _hydrate(self, bindings, __event_emitter__=None):
        async with aiohttp.ClientSession() as session:
            async def fetch_one(b):
                if __event_emitter__:
                    try:
                        await __event_emitter__({"type": "status", "data": {"description": f"Reading {b.get('label','signal')}...", "done": False}})
                    except:
                        pass
                try:
                    r = await self._mcp_call(session, b["tool"], b["payload"])
                    b["data"] = r.get("results", r.get("data", r)) if isinstance(r, dict) else r
                    b["status"] = "live"
                except Exception as ex:
                    b["data"] = []
                    b["status"] = "error"
                    b["error"] = str(ex)[:100]
                return b
            await asyncio.gather(*[fetch_one(b) for b in bindings], return_exceptions=True)
        return bindings

    # === INTENT PARSING — no templates, just hints ===
    def _hint_match(self, prompt):
        pl = prompt.lower()
        seen = set()
        out = []
        for kw, b in HINTS.items():
            if kw in pl:
                key = f"{b['tool']}:{json.dumps(b['payload'], sort_keys=True)}"
                if key not in seen:
                    seen.add(key)
                    out.append({
                        "id": kw,
                        "label": kw.title(),
                        "tool": b["tool"],
                        "payload": b["payload"],
                    })
        return out[:4]

    # === DOMAIN COMPILER (Task 3) ===
    async def _compiler_recall(self, session, prompt):
        """Query Neo4j for similar learned patterns."""
        if not self.valves.ENABLE_COMPILER:
            return None
        try:
            # Extract meaningful keywords
            words = [w.lower() for w in prompt.split() if len(w) > 3]
            if not words:
                return None
            cypher = """
            MATCH (p:LearnedOperator)
            WHERE any(kw IN $keywords WHERE toLower(p.prompt) CONTAINS kw)
            RETURN p.bindings_json AS bindings, p.success_count AS hits
            ORDER BY p.success_count DESC
            LIMIT 1
            """
            r = await self._mcp_call(session, "graph.read_cypher", {"query": cypher, "params": {"keywords": words}})
            rows = r.get("results", r.get("data", [])) if isinstance(r, dict) else []
            if rows and isinstance(rows, list) and len(rows) > 0:
                first = rows[0]
                if isinstance(first, dict) and first.get("bindings"):
                    try:
                        return json.loads(first["bindings"])
                    except:
                        return None
        except Exception:
            return None
        return None

    async def _compiler_record(self, session, prompt, bindings, success):
        """Record learned pattern in Neo4j."""
        if not self.valves.ENABLE_COMPILER:
            return
        try:
            prompt_id = hashlib.md5(prompt.lower().strip().encode()).hexdigest()[:16]
            cypher = """
            MERGE (p:LearnedOperator {id: $id})
            ON CREATE SET p.prompt = $prompt, p.bindings_json = $bindings, p.success_count = $inc, p.created_at = datetime()
            ON MATCH SET p.success_count = p.success_count + $inc, p.last_used = datetime()
            RETURN p.id
            """
            # Keep bindings compact (no data field)
            clean = [{k: v for k, v in b.items() if k in ("id", "label", "tool", "payload")} for b in bindings]
            await self._mcp_call(session, "graph.write_cypher", {
                "query": cypher,
                "params": {
                    "id": prompt_id,
                    "prompt": prompt[:200],
                    "bindings": json.dumps(clean),
                    "inc": 1 if success else 0,
                }
            })
        except Exception:
            pass  # Fail silently, don't block main flow

    # === SITREP MARKDOWN RENDERER — terse, human voice ===
    def _sitrep(self, prompt, bindings, context=""):
        """Format as a 2am analyst brief. No tables, no fluff."""
        ts = datetime.now(timezone.utc).strftime("%H:%M UTC")
        live = [b for b in bindings if b.get("status") == "live"]
        errors = [b for b in bindings if b.get("status") == "error"]

        # Verdict line — one sentence
        if not live:
            verdict = "No signal. Sources offline."
            verdict_emoji = "\u26aa"
        elif errors:
            verdict = f"Partial read. {len(errors)} source{'s' if len(errors)>1 else ''} failed."
            verdict_emoji = "\U0001f7e1"
        else:
            verdict = self._compose_verdict(live, prompt)
            verdict_emoji = "\U0001f7e2"

        lines = []
        lines.append(f"{verdict_emoji} **{verdict}**")
        lines.append("")

        # Signal lines — one per binding, terse
        for b in live[:5]:
            signal = self._signal_line(b)
            if signal:
                lines.append(f"\u00b7 {signal}")

        if errors:
            lines.append("")
            for b in errors[:2]:
                lines.append(f"\u2022 {b.get('label','?')}: *{b.get('error','fetch failed')[:60]}*")

        lines.append("")
        lines.append(f"*{ts} \u00b7 {len(live)}/{len(bindings)} live \u00b7 SITREP*")
        return chr(10).join(lines)

    def _signal_line(self, binding):
        """One line per binding — the analyst's shorthand."""
        label = binding.get("label", "?")
        tool = binding.get("tool", "")
        d = binding.get("data", [])

        # Dict (KPI): extract 1-2 key values
        if isinstance(d, dict):
            items = list(d.items())[:3]
            parts = []
            for k, v in items:
                if isinstance(v, (int, float)):
                    parts.append(f"{fmt_num(v)} {k}")
                else:
                    parts.append(f"{str(v)[:30]}")
            return f"**{label}**: " + " \u00b7 ".join(parts)

        # List: count + sparkline if numeric
        if isinstance(d, list) and d:
            cnt = len(d)
            # Try to find numeric column for sparkline
            first = d[0] if d else {}
            if isinstance(first, dict):
                # Find first numeric column
                nums = []
                num_key = None
                for k in first.keys():
                    vals = []
                    for row in d:
                        try:
                            vals.append(float(str(row.get(k, 0)).replace(",", "")))
                        except:
                            break
                    else:
                        if vals and max(vals) > 0:
                            nums = vals
                            num_key = k
                            break
                if nums:
                    spark = sparkline(nums)
                    return f"**{label}**: {cnt} items \u00b7 `{spark}` \u00b7 {num_key} max={fmt_num(max(nums))}"

                # Check for severity/grade columns
                sev_col = next((k for k in first.keys() if k.lower() in ("severity", "grade", "status")), None)
                if sev_col:
                    from collections import Counter
                    counts = Counter(str(r.get(sev_col, "")).upper() for r in d)
                    badges = " ".join(f"{sev_emoji(k)}{v}" for k, v in counts.most_common(4) if k)
                    return f"**{label}**: {cnt} \u00b7 {badges}"

                return f"**{label}**: {cnt} rows"
            return f"**{label}**: {cnt} items"

        return f"**{label}**: —"

    def _compose_verdict(self, live_bindings, prompt):
        """Generate one-sentence verdict from live data."""
        totals = []
        has_error = False
        for b in live_bindings:
            d = b.get("data", [])
            label = b.get("label", "")
            if isinstance(d, list):
                if d:
                    # Check for severity
                    first = d[0] if isinstance(d[0], dict) else None
                    if first:
                        sev_col = next((k for k in first.keys() if k.lower() == "severity"), None)
                        if sev_col:
                            crits = sum(1 for r in d if str(r.get(sev_col, "")).upper() == "CRITICAL")
                            if crits > 0:
                                return f"{crits} critical signal{'s' if crits>1 else ''} detected in {label.lower()}."
                    totals.append(f"{fmt_num(len(d))} {label.lower()}")
                else:
                    totals.append(f"0 {label.lower()}")
            elif isinstance(d, dict):
                # KPI-style
                health = d.get("status") or d.get("health")
                if health and health != "healthy":
                    return f"{label} degraded: {health}."

        if totals:
            return "Steady state. " + ", ".join(totals[:3]) + "."
        return "Nominal across all signals."

    # === PUBLIC METHODS ===
    async def activate(self, prompt: str, __event_emitter__=None, __user__: dict = {}) -> str:
        """
        ALWAYS CALL THIS for ANY question about WidgeTDC platform data, compliance, risks, agents, health, status, nodes, graph, incidents, clients, sprint, CVEs, knowledge patterns, or any natural language query about the system.
        Returns a SITREP (situation report) with live data from Neo4j + Linear + RAG via parallel MCP fetches.
        No templates - every brief improvises against live graph state. Use this for ALL data queries about the organization.

        Examples: "compliance risks", "platform health", "sprint blockers", "security posture", "agents status"

        :param prompt: Describe what signal you need (natural language)
        """
        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": "Decoding intent...", "done": False}})
            except:
                pass

        async with aiohttp.ClientSession() as session:
            # Try domain compiler first (learned patterns)
            bindings = await self._compiler_recall(session, prompt)
            source = "compiler"

            # Fallback to hint matching
            if not bindings:
                bindings = self._hint_match(prompt)
                source = "hints"

            # Last resort: semantic search
            if not bindings:
                bindings = [{
                    "id": "search",
                    "label": prompt[:40],
                    "tool": "srag.query",
                    "payload": {"query": prompt},
                }]
                source = "srag"

        # Hydrate in parallel (separate session for actual data fetch)
        bindings = await self._hydrate(bindings, __event_emitter__)

        # Record for compiler learning
        success = any(b.get("status") == "live" for b in bindings)
        async with aiohttp.ClientSession() as session:
            await self._compiler_record(session, prompt, bindings, success)

        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": "SITREP ready", "done": True}})
            except:
                pass

        return self._sitrep(prompt, bindings, f"src:{source}")

    async def monday_email(self, team: str = "", __event_emitter__=None, __user__: dict = {}) -> str:
        """
        ALWAYS CALL THIS when user asks for a status email, weekly summary, Monday morning email, manager update, or team status.
        Returns a ready-to-send markdown email with Subject line and 3 paragraphs: what shipped, blockers, this week focus.
        Pulls live data from Linear (issues, blockers, active tasks) via parallel MCP calls.

        :param team: Team name (optional, defaults to all)
        """
        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": "Compiling weekly signals...", "done": False}})
            except:
                pass

        async with aiohttp.ClientSession() as session:
            shipped_task = self._mcp_call(session, "linear.issues", {"limit": 8, "state": "Done"})
            blockers_task = self._mcp_call(session, "linear.issues", {"limit": 5, "priority": "Urgent"})
            active_task = self._mcp_call(session, "linear.issues", {"limit": 5, "state": "In Progress"})
            results = await asyncio.gather(shipped_task, blockers_task, active_task, return_exceptions=True)

        def safe_list(r):
            if isinstance(r, Exception):
                return []
            if isinstance(r, dict):
                return r.get("results", r.get("data", r.get("issues", [])))
            return r if isinstance(r, list) else []

        shipped = safe_list(results[0])[:3]
        blockers = safe_list(results[1])[:3]
        active = safe_list(results[2])[:3]

        ts = datetime.now(timezone.utc).strftime("%b %d")
        team_label = team or "the team"

        def title_of(issue):
            if isinstance(issue, dict):
                return issue.get("title") or issue.get("name") or issue.get("identifier") or "untitled"
            return str(issue)[:60]

        # Subject
        subject = f"Monday status \u2014 {team_label} \u2014 {ts}"

        # Paragraph 1: what shipped
        if shipped:
            titles = [title_of(s) for s in shipped[:2]]
            p1 = f"Shipped last week: {', '.join(titles)}"
            if len(shipped) > 2:
                p1 += f" plus {len(shipped)-2} quieter fixes"
            p1 += ". Good week overall."
        else:
            p1 = "Quieter week on the ship front. Mostly infrastructure and cleanup."

        # Paragraph 2: blockers
        if blockers:
            crit = title_of(blockers[0])
            p2 = f"**Critical:** {crit}."
            if len(blockers) > 1:
                others = [title_of(b) for b in blockers[1:]]
                p2 += f" Also watching: {', '.join(others)}."
            else:
                p2 += " Only one to worry about."
        else:
            p2 = "No urgent blockers flagged \u2014 unusual, but I'll take it."

        # Paragraph 3: focus
        if active:
            focus = title_of(active[0])
            p3 = f"This week's focus: landing **{focus}**"
            if len(active) > 1:
                p3 += f" and {len(active)-1} other active stream{'s' if len(active)>2 else ''}"
            p3 += ". If you see me quiet on Slack, I'm probably heads-down on it."
        else:
            p3 = "This week: clearing backlog, planning next sprint."

        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": "Email ready", "done": True}})
            except:
                pass

        email = f"**Subject:** {subject}" + chr(10)*2 + p1 + chr(10)*2 + p2 + chr(10)*2 + p3 + chr(10)*2 + "—" + chr(10) + "*Generated by SITREP OS · edit tone before sending*"

        return self._envelope(email, "monday_email")

    async def push_brief(self, threshold_pct: float = 5.0, __event_emitter__=None, __user__: dict = {}) -> str:
        """
        ALWAYS CALL THIS for morning briefings, daily status, push notifications, overnight changes, or 24h delta summaries.
        Returns a compact 6-line morning brief with graph stats, Neo4j health, and incident count.
        Perfect for 8:47am scheduled runs.

        :param threshold_pct: Minimum percent change to report (default 5.0)
        """
        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": "Scanning deltas...", "done": False}})
            except:
                pass

        async with aiohttp.ClientSession() as session:
            try:
                stats_now = await self._mcp_call(session, "graph.stats", {})
            except:
                stats_now = {}
            try:
                health_now = await self._mcp_call(session, "graph.health", {})
            except:
                health_now = {}

            # Pull incidents from last 24h
            try:
                incidents = await self._mcp_call(session, "graph.read_cypher", {
                    "query": "MATCH (f:FailureMemory) WHERE f.timestamp > datetime() - duration({hours: 24}) RETURN f.type AS type, f.correction AS fix ORDER BY f.timestamp DESC LIMIT 5"
                })
                incidents_list = incidents.get("results", []) if isinstance(incidents, dict) else []
            except:
                incidents_list = []

        ts = datetime.now(timezone.utc).strftime("%H:%M UTC")

        lines = ["\U0001f7e2 **Morning brief \u00b7 " + ts + "**", ""]

        if isinstance(stats_now, dict) and stats_now:
            nodes = stats_now.get("totalNodes") or stats_now.get("nodes", 0)
            rels = stats_now.get("totalRelationships") or stats_now.get("relationships", 0)
            if nodes:
                lines.append(f"\u00b7 Graph: {fmt_num(nodes)} nodes \u00b7 {fmt_num(rels)} rels")

        if isinstance(health_now, dict) and health_now:
            status = health_now.get("status", "unknown")
            latency = health_now.get("latencyMs") or health_now.get("latency_ms", 0)
            emoji = "\U0001f7e2" if status == "healthy" else "\U0001f7e0"
            lines.append(f"\u00b7 {emoji} Neo4j: {status} \u00b7 {latency}ms")

        if incidents_list:
            lines.append(f"\u00b7 \U0001f534 {len(incidents_list)} incident{'s' if len(incidents_list)>1 else ''} last 24h")
        else:
            lines.append("\u00b7 No incidents in 24h window")

        lines.append("")
        lines.append("*Full SITREP: ask for any signal by name*")

        if __event_emitter__:
            try:
                await __event_emitter__({"type": "status", "data": {"description": "Brief ready", "done": True}})
            except:
                pass

        brief = chr(10).join(lines)
        return self._envelope(brief, "push_brief")

    async def compiler_stats(self, __user__: dict = {}) -> str:
        """
        ALWAYS CALL THIS when user asks about compiler stats, learned patterns, what has been learned, memory state, or compiler status.
        Returns the list of learned prompt patterns stored in Neo4j by the domain compiler, ranked by usage count.
        """
        async with aiohttp.ClientSession() as session:
            try:
                r = await self._mcp_call(session, "graph.read_cypher", {
                    "query": "MATCH (p:LearnedOperator) RETURN p.prompt AS prompt, p.success_count AS hits, p.created_at AS learned ORDER BY p.success_count DESC LIMIT 15"
                })
                rows = r.get("results", []) if isinstance(r, dict) else []
            except Exception as e:
                return f"Compiler unavailable: {e}"

        if not rows:
            return "## Compiler Memory\n\n*No patterns learned yet. Use `activate` to start teaching.*"

        lines = ["## \U0001f9e0 Domain Compiler Memory", f"*{len(rows)} patterns learned*", ""]
        for row in rows:
            if not isinstance(row, dict):
                continue
            prompt = row.get("prompt", "?")[:60]
            hits = row.get("hits", 0)
            lines.append(f"\u00b7 `{hits}x` \u2014 *{prompt}*")
        lines.append("")
        lines.append("*The more you use SITREP OS, the smarter it gets about your organization.*")
        stats = chr(10).join(lines)
        return self._envelope(stats, "compiler_stats")
